// Obter todos os itens de entrada
const items = $input.all();

//console.log('Estrutura completa dos itens:', JSON.stringify(items, null, 2));

function extractFieldFromMessages(array, field) {
  // Iterar sobre os itens
  return array.flatMap(item => {
    // Obter o array de mensagens
    const messages = item.json.messages || [];
    // Parsear cada string JSON no array e extrair o campo desejado
    return messages.map(message => {
      try {
        const parsedMessage = JSON.parse(message); // Parsear a string JSON
        return parsedMessage[field]; // Retornar o campo desejado
      } catch (error) {
        console.error('Erro ao parsear mensagem:', message, error);
        return null; // Ignorar mensagens inválidas
      }
    });
  }).filter(value => typeof value === 'string'); // Filtrar valores não string
}

// Extrair o campo 'text' de todas as mensagens
const msgs = extractFieldFromMessages(items, 'text');

//console.log('Mensagens extraídas:', msgs);

// Remover duplicados diretamente das mensagens extraídas
const uniqueMessages = [...new Set(msgs)];

console.log('Mensagens únicas:', uniqueMessages);

// Construir o resultado
const result = [
  {
    json: {
      messages:uniqueMessages,
    },
  },
];

// Retornar o resultado
return result;

// Obtenha o texto da entrada
const inputText = $input.first().json.output || "";
// Separe o texto em um array utilizando '\n' como delimitador
const textBlocks = inputText.split('\n').filter(block => block.trim() !== ""); // Filtra linhas vazias
// Obtenha o tipo da mensagem do nó 'SetFieldsBasic'
const type_msg = $('SetFieldsBasic').first().json.type;
// Função para identificar o tipo de mídia com base no link ou no argumento 'tipo'
const determineMediaType = (url) => {
  // Extrai o argumento 'tipo' da URL manualmente
  const tipoMatch = url.match(/[?&]tipo=([^&]+)/);
  if (tipoMatch) {
    return tipoMatch[1].replace(')','').replace('(',''); // Retorna o valor de 'tipo' na URL, se presente
  }
  // Expressões regulares para identificar o tipo de mídia com base na extensão do link
  const pdfRegex = /\.pdf$/i;
  const docRegex = /\.(doc|docx)$/i;
  const imageRegex = /\.(jpg|jpeg|png|gif|bmp|svg|webp)$/i;
  const videoRegex = /\.(mp4|mov|avi|wmv|mkv|flv|webm)$/i;
  const audioRegex = /\.(mp3|wav|ogg|m4a)$/i;
  if (pdfRegex.test(url)) return 'pdf';
  if (docRegex.test(url)) return 'doc';
  if (imageRegex.test(url)) return 'image';
  if (videoRegex.test(url)) return 'video';
  if (audioRegex.test(url)) return 'audioMessage';
  return null;
};
// Função para extrair a URL de um texto
const extractUrl = (text) => {
  const urlRegex = /(https?:\/\/[^\s]+)/g; // Captura qualquer URL em um texto
  const match = text.match(urlRegex);
  return match ? match[0] : null; // Retorna a primeira URL encontrada
};

// Não precisamos mais dessa função, pois todas as mídias serão tratadas individualmente

// Preparação para processamento
let outputArray = []; // Armazena blocos processados
let firstBlockProcessed = false;
let mediaItems = [];
let textItems = [];

// Processa o primeiro bloco separadamente (regras especiais)
if (textBlocks.length > 0) {
  const firstBlock = textBlocks[0];
  const url = extractUrl(firstBlock);
  const mediaType = url ? determineMediaType(url) : null;

  // Adiciona o texto do primeiro bloco
  const textWithoutUrl = firstBlock.replace(url || '', '').trim();
  if (textWithoutUrl) {
    textItems.push({
      block: null,
      text: textWithoutUrl,
      type: type_msg
    });
  }

  // Adiciona a mídia do primeiro bloco, se existir
  if (url && mediaType) {
    mediaItems.push({
      block: url,
      text: null,
      type: mediaType
    });
  }

  firstBlockProcessed = true;
}

// Processa os blocos restantes
for (let i = 1; i < textBlocks.length; i++) {
  const block = textBlocks[i];
  const url = extractUrl(block);
  const mediaType = url ? determineMediaType(url) : null;
  const adjustedMediaType = mediaType === 'audioMessage' ? 'conversation' : mediaType;

  // Adiciona a mídia, se existir
  if (url && adjustedMediaType) {
    mediaItems.push({
      block: url,
      text: null,
      type: adjustedMediaType
    });
  }

  // Adiciona o texto sem a URL, se houver conteúdo
  const textWithoutUrl = block.replace(url || '', '').trim();
  if (textWithoutUrl) {
    textItems.push({
      block: null,
      text: textWithoutUrl,
      type: 'conversation'
    });
  }
}

// NOVA ESTRATÉGIA DE PROCESSAMENTO:
// 1. Primeiro bloco: mantém o texto original (type_msg), se houver
// 2. Todas as mídias: cada mídia terá seu próprio bloco separado (independente do tipo)
// 3. Textos adicionais: todos agrupados em um bloco

// Adiciona o primeiro bloco de texto (com tipo original)
if (textItems.length > 0) {
  outputArray.push(textItems[0]);
}

// Adiciona cada mídia individualmente em seu próprio bloco
// Desta forma, nenhum tipo de mídia será agrupado no mesmo bloco
mediaItems.forEach(item => {
  outputArray.push(item);
});

// Adiciona o bloco de textos adicionais (se houver mais de um texto)
if (textItems.length > 1) {
  const additionalTexts = textItems.slice(1);
  const combinedText = additionalTexts.map(item => item.text).join('\n');

  if (combinedText) {
    outputArray.push({
      block: null,
      text: combinedText,
      type: 'conversation'
    });
  }
}

// Limita a no máximo 3 blocos
outputArray = outputArray.slice(0, 5);

// Filtra itens válidos antes de retornar
return outputArray
  .filter(item => item.block !== null || item.text !== null) // Remove objetos vazios
  .map(item => ({ json: item }));
